that's a simple dp problem
init 0 row with ones
and after that sum-up all the  possible paths that ends in the given cell
something like that:
the complexity of a given approach: O(nm), space: O(m)

```
   public static int findAllPaths(char[][] matrix) {
        if (matrix == null || matrix.length == 0 || matrix[0] == null || matrix[0].length == 0) return 0;
        int n = matrix.length, m = matrix[0].length;
        int[] prev = new int[m];
        int[] curr = new int[m];
        Arrays.fill(prev, 1);
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < m; j++) {
                char c = matrix[i][j];
                curr[j] = 0;
                if (c == '\\') {
                    if (j > 0 && matrix[i - 1][j - 1] == '\\') {
                        curr[j] += matrix[i - 1][j - 1];
                    }
                    if (matrix[i - 1][j] == '/') {
                        curr[j] += matrix[i - 1][j];
                    }
                } else {
                    // => /
                    if (matrix[i - 1][j] == '\\') {
                        curr[j] += matrix[i - 1][j];
                    }
                    if (j < m - 1 && matrix[i - 1][j + 1] == '/') {
                        curr[j] += matrix[i - 1][j + 1];
                    }
                }
            }
            int[] tmp = prev;
            prev = curr;
            curr = tmp;
        }

        int result = 0;
        for (int p : prev) {
            result += p;
        }
        return result;
    }

